const problemsData = require('../../data/problems.json');

function getDifficultyRange(difficulty) {
  switch (difficulty) {
    case 'easy':
      return { min: 0, max: 1200 };
    case 'medium':
      return { min: 1201, max: 2200 };
    case 'hard':
      return { min: 2201, max: Infinity };
    default:
      return { min: 0, max: Infinity };
  }
}

function countDifficultyBreakdown(problems) {
  const breakdown = { easy: 0, medium: 0, hard: 0 };
  problems.forEach(p => {
    if (p.difficulty <= 1200) breakdown.easy++;
    else if (p.difficulty <= 2200) breakdown.medium++;
    else breakdown.hard++;
  });
  return breakdown;
}

function solve({ difficulty, limit = 50, includeComponents = false }) {
  const { min, max } = getDifficultyRange(difficulty);

  // Filter problems by difficulty range
  const filtered = problemsData.filter(p => p.difficulty >= min && p.difficulty <= max);

  // Sort by roundId ascending (deterministic ordering)
  filtered.sort((a, b) => a.roundId - b.roundId);

  // Apply limit (max 50)
  const appliedLimit = Math.min(limit, 50);
  const limited = filtered.slice(0, appliedLimit);

  // Prepare componentLanguages if requested
  if (includeComponents) {
    limited.forEach(p => {
      if (p.componentLanguages && Array.isArray(p.componentLanguages)) {
        p.componentLanguages = p.componentLanguages.slice().sort();
      }
    });
  }

  return {
    totalProblems: problemsData.length,
    filteredCount: filtered.length,
    appliedLimit,
    difficultyBreakdown: countDifficultyBreakdown(filtered),
    problems: limited,
  };
}

module.exports = { solve };
